// driver on first use.
func NewPlatformCompatStub(
	impl IPlatformCompatServer,
) IPlatformCompat {
	wrapper := &platformCompatStubWrapper{impl: impl}
	stub := &PlatformCompatStub{Impl: wrapper}
	wrapper.stubBinder = binder.NewStubBinder(stub)
	return wrapper
}
